const MAX_REQUEST_ID_LENGTH = 128;
const MAX_AGENT_LENGTH = 100;
const MAX_TASK_LENGTH = 64;
const MAX_SOURCE_LENGTH = 50;
const VALID_PRIORITIES = ['high', 'normal', 'low'];

function isPlainObject(value) {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

function invalid(field) {
  return {
    json: {
      valid: false,
      invalid_field: field,
      message: '请求内容不符合要求',
    },
  };
}

const body = ($json && $json.body) || {};

// request_id：调用方提供了就 trim 后直接复用，未提供则用
// 同一次 n8n execution + 当前 item 下标拼出稳定值——
// 同一次 execution 内的重试（HTTP Request 节点自身的
// 重试、或 n8n 对整个 workflow 的重试）都会复用相同的
// $execution.id，不会每次重新随机生成 UUID 或用当前毫秒
// 时间戳作为唯一 request_id。
let requestId = typeof body.request_id === 'string' ? body.request_id.trim() : '';
if (!requestId) {
  requestId = `n8n-${$execution.id}-${$itemIndex}`;
}

if (!requestId || requestId.length > MAX_REQUEST_ID_LENGTH) {
  return invalid('request_id');
}

const assignedAgent = typeof body.assigned_agent === 'string' ? body.assigned_agent.trim() : '';
if (!assignedAgent || assignedAgent.length > MAX_AGENT_LENGTH) {
  return invalid('assigned_agent');
}

const task = typeof body.task === 'string' ? body.task.trim() : '';
if (!task || task.length > MAX_TASK_LENGTH) {
  return invalid('task');
}

const priority = (typeof body.priority === 'string' && body.priority.trim())
  ? body.priority.trim()
  : 'normal';
if (!VALID_PRIORITIES.includes(priority)) {
  return invalid('priority');
}

let context = {};
if (body.context !== undefined && body.context !== null) {
  if (!isPlainObject(body.context)) {
    return invalid('context');
  }
  context = body.context;
}

const source = (typeof body.source === 'string' && body.source.trim())
  ? body.source.trim()
  : 'n8n';
if (source.length === 0 || source.length > MAX_SOURCE_LENGTH) {
  return invalid('source');
}

return {
  json: {
    valid: true,
    normalized: {
      request_id: requestId,
      source,
      assigned_agent: assignedAgent,
      task,
      context,
      priority,
    },
  },
};

const item = $input.first().json;

// 成功路径：item 直接是后端 202/200 响应体（含
// id/request_id/duplicate 等字段）。
if (item && typeof item === 'object' && item.duplicate !== undefined && item.id) {
  return [{
    json: {
      ok: true,
      task_id: item.id,
      request_id: item.request_id,
      duplicate: item.duplicate,
      status: item.status,
      message: item.message,
      httpStatus: item.duplicate ? 200 : 202,
    },
  }];
}

// 错误路径：HTTP Request 节点 onError=continueErrorOutput
// 产生的 item，形如 { error: {...} }。不同版本/错误类型下
// 具体字段名不完全一致，这里做多路径兵底探测 HTTP 状态
// 码，探测不到时安全降级为 TEMPORARY_FAILURE（而不是猜测
// 成某个更具体、但可能错误的分类）。
const error = (item && item.error) || {};

function extractStatusCode() {
  const candidates = [
    error.httpCode,
    error.statusCode,
    error.status,
    error.cause && error.cause.response && error.cause.response.status,
    error.cause && error.cause.httpCode,
  ];
  for (const candidate of candidates) {
    if (candidate === undefined || candidate === null) continue;
    const parsed = parseInt(candidate, 10);
    if (!Number.isNaN(parsed)) return parsed;
  }
  return null;
}

const statusCode = extractStatusCode();

const STATUS_TO_CODE = {
  401: ['AUTH_FAILED', '任务网关鉴权失败', 401],
  404: ['AGENT_NOT_FOUND', '指定的 AI 员工不存在', 404],
  422: ['INVALID_REQUEST', '任务内容不符合要求', 422],
  503: ['GATEWAY_NOT_CONFIGURED', '任务网关暂未配置', 503],
};

let code = 'TEMPORARY_FAILURE';
let message = '任务提交暂时失败，请稍后重试';
let httpStatus = 502;

if (statusCode !== null && STATUS_TO_CODE[statusCode]) {
  const mapped = STATUS_TO_CODE[statusCode];
  code = mapped[0];
  message = mapped[1];
  httpStatus = mapped[2];
}

return [{
  json: {
    ok: false,
    code,
    message,
    httpStatus,
  },
}];
